 1→-- Migration 0032: Objective table, has_objective relation, supports relation, observes OUT extension
 2→-- Step 01-01 of the objective-behavior feature
 3→
 4→BEGIN TRANSACTION;
 5→
 6→-- Objective: strategic goal node
 7→DEFINE TABLE objective SCHEMAFULL;
 8→
 9→DEFINE FIELD title ON objective TYPE string;
10→DEFINE FIELD description ON objective TYPE option<string>;
11→DEFINE FIELD target_date ON objective TYPE option<string>;
12→DEFINE FIELD priority ON objective TYPE string
13→  ASSERT $value IN ["low", "medium", "high", "critical"];
14→DEFINE FIELD status ON objective TYPE string
15→  ASSERT $value IN ["draft", "active", "completed", "archived", "expired"];
16→
17→-- Success criteria (array of KPI objects)
18→DEFINE FIELD success_criteria ON objective TYPE option<array<object>>;
19→DEFINE FIELD success_criteria[*].metric_name ON objective TYPE string;
20→DEFINE FIELD success_criteria[*].target_value ON objective TYPE float;
21→DEFINE FIELD success_criteria[*].current_value ON objective TYPE float;
22→DEFINE FIELD success_criteria[*].unit ON objective TYPE string;
23→
24→-- Provenance
25→DEFINE FIELD workspace ON objective TYPE record<workspace>;
26→DEFINE FIELD source_message ON objective TYPE option<record<message>>;
27→DEFINE FIELD created_by ON objective TYPE option<record<identity>>;
28→DEFINE FIELD created_at ON objective TYPE datetime;
29→DEFINE FIELD updated_at ON objective TYPE option<datetime>;
30→
31→-- Embedding for semantic matching
32→DEFINE FIELD embedding ON objective TYPE option<array<float>>;
33→
34→-- Indexes
35→DEFINE INDEX objective_workspace_status ON objective FIELDS workspace, status;
36→DEFINE INDEX objective_target_date ON objective FIELDS target_date;
37→DEFINE INDEX idx_objective_embedding ON objective FIELDS embedding HNSW DIMENSION 1536 DIST COSINE;
38→
39→-- has_objective: links project or workspace to its objectives
40→DEFINE TABLE has_objective TYPE RELATION IN project | workspace OUT objective SCHEMAFULL;
41→DEFINE FIELD added_at ON has_objective TYPE datetime;
42→
43→-- supports: links an intent to the strategic objective it serves
44→DEFINE TABLE supports TYPE RELATION IN intent OUT objective SCHEMAFULL;
45→DEFINE FIELD alignment_score ON supports TYPE float
46→  ASSERT $value >= 0.0 AND $value <= 1.0;
47→DEFINE FIELD alignment_method ON supports TYPE string
48→  ASSERT $value IN ["embedding", "manual", "rule"];
49→DEFINE FIELD reasoning ON supports TYPE option<string>;
50→DEFINE FIELD added_at ON supports TYPE option<datetime>;
51→DEFINE INDEX supports_out ON supports FIELDS out;
52→
53→-- Extend observes OUT to include objective
54→ALTER TABLE observes TYPE RELATION IN observation OUT project | feature | task | decision | question | intent | git_commit | observation | objective;
55→
56→COMMIT TRANSACTION;
57→

 1→-- Migration 0033: Behavior table, exhibits relation, learning_evidence OUT extension
 2→-- Step 01-02 of the objective-behavior feature
 3→
 4→BEGIN TRANSACTION;
 5→
 6→-- Behavior: agent craftsmanship metric record (append-only)
 7→DEFINE TABLE behavior SCHEMAFULL;
 8→
 9→DEFINE FIELD metric_type ON behavior TYPE string
10→  ASSERT $value IN [
11→    "TDD_Adherence",
12→    "Security_First",
13→    "Conciseness",
14→    "Review_Responsiveness",
15→    "Documentation_Quality"
16→  ];
17→DEFINE FIELD score ON behavior TYPE float
18→  ASSERT $value >= 0.0 AND $value <= 1.0;
19→
20→-- Telemetry source data (metric-specific, flexible schema)
21→DEFINE FIELD source_telemetry ON behavior TYPE object FLEXIBLE;
22→
23→-- Context
24→DEFINE FIELD workspace ON behavior TYPE record<workspace>;
25→DEFINE FIELD session ON behavior TYPE option<record<agent_session>>;
26→DEFINE FIELD created_at ON behavior TYPE datetime;
27→
28→-- Indexes
29→DEFINE INDEX behavior_workspace_metric ON behavior FIELDS workspace, metric_type;
30→DEFINE INDEX behavior_session ON behavior FIELDS session;
31→DEFINE INDEX behavior_created_at ON behavior FIELDS created_at;
32→
33→-- exhibits: links an agent identity to a behavior record
34→DEFINE TABLE exhibits TYPE RELATION IN identity OUT behavior SCHEMAFULL;
35→DEFINE FIELD created_at ON exhibits TYPE option<datetime>;
36→DEFINE FIELD added_at ON exhibits TYPE option<datetime>;
37→
38→-- Extend learning_evidence OUT to include behavior
39→ALTER TABLE learning_evidence TYPE RELATION IN learning OUT message | trace | observation | agent_session | behavior;
40→
41→-- Extend observes OUT to include behavior
42→ALTER TABLE observes TYPE RELATION IN observation OUT project | feature | task | decision | question | intent | git_commit | observation | objective | behavior;
43→
44→COMMIT TRANSACTION;
45→

1→-- Add BM25 full-text search index for objective title.
2→-- Uses the existing entity_search analyzer defined in migration 0002.
3→
4→BEGIN TRANSACTION;
5→
6→DEFINE INDEX OVERWRITE idx_objective_fulltext ON objective FIELDS title FULLTEXT ANALYZER entity_search BM25(1.2, 0.75);
7→
8→COMMIT TRANSACTION;
9→

1→-- Add embedding field to intent table for objective alignment via KNN search
2→
3→BEGIN TRANSACTION;
4→
5→DEFINE FIELD OVERWRITE embedding ON intent TYPE option<array<float>>;
6→DEFINE INDEX idx_intent_embedding ON intent FIELDS embedding HNSW DIMENSION 1536 DIST COSINE;
7→
8→COMMIT TRANSACTION;
9→

 1→-- Migration 0036: Add objective/behavior edge tables to graph traversal functions
 2→-- Adds supports, exhibits, has_objective to fn::entity_edges, fn::edges_between,
 3→-- fn::graph_neighbors. Adds objective/behavior collection to fn::workspace_entity_ids
 4→-- and fn::project_entity_ids.
 5→
 6→DEFINE FUNCTION OVERWRITE fn::entity_edges($entity: record, $lim: int) {
 7→  RETURN SELECT id, `in`, out, kind, confidence
 8→    FROM entity_relation, belongs_to, has_feature, has_task, has_project,
 9→         depends_on, owns, observes, suggests_for, subtask_of,
10→         governing, protects, triggered_by, gates,
11→         supports, exhibits, has_objective
12→    WHERE `in` = $entity OR out = $entity
13→    LIMIT $lim;
14→};
15→
16→DEFINE FUNCTION OVERWRITE fn::edges_between($ids: array) {
17→  RETURN SELECT id, `in`, out, kind, confidence
18→    FROM entity_relation, belongs_to, has_feature, has_task, has_project,
19→         depends_on, owns, observes, suggests_for, subtask_of,
20→         governing, protects, triggered_by, gates,
21→         supports, exhibits, has_objective
22→    WHERE `in` IN $ids AND out IN $ids;
23→};
24→
25→DEFINE FUNCTION OVERWRITE fn::graph_neighbors($ids: array) {
26→  RETURN SELECT `in`, out
27→    FROM entity_relation, belongs_to, has_feature, has_task, has_project,
28→         depends_on, owns, observes, suggests_for, subtask_of,
29→         governing, protects, triggered_by, gates,
30→         supports, exhibits, has_objective
31→    WHERE `in` IN $ids OR out IN $ids;
32→};
33→
34→DEFINE FUNCTION OVERWRITE fn::workspace_entity_ids($ws: record<workspace>) {
35→  LET $projects = (SELECT VALUE out FROM has_project WHERE `in` = $ws);
36→  LET $features = (SELECT VALUE out FROM has_feature WHERE `in` IN $projects);
37→  LET $tasks = (SELECT VALUE out FROM has_task WHERE `in` IN $features);
38→  LET $belongs_project = (SELECT VALUE `in` FROM belongs_to WHERE out IN $projects);
39→  LET $belongs_feature = (SELECT VALUE `in` FROM belongs_to WHERE out IN $features);
40→  LET $identities = (SELECT VALUE `in` FROM member_of WHERE out = $ws);
41→  LET $provenance = (
42→    SELECT VALUE out FROM extraction_relation
43→    WHERE `in` IN (
44→      SELECT VALUE id FROM message
45→      WHERE conversation IN (
46→        SELECT VALUE id FROM conversation WHERE workspace = $ws
47→      )
48→    )
49→  );
50→  LET $policies = (SELECT VALUE `in` FROM protects WHERE out = $ws AND `in`.status IN ['active', 'testing']);
51→  LET $intents = (SELECT VALUE id FROM intent WHERE workspace = $ws AND status NOT IN ['completed', 'vetoed', 'failed']);
52→  LET $agent_sessions = (SELECT VALUE out FROM gates WHERE `in` IN $intents);
53→  LET $objectives = (SELECT VALUE out FROM has_objective WHERE `in` = $ws OR `in` IN $projects);
54→  LET $behaviors = (SELECT VALUE id FROM behavior WHERE workspace = $ws);
55→  RETURN array::distinct(
56→    [$ws] + $projects + $features + $tasks +
57→    $belongs_project + $belongs_feature +
58→    $identities + $provenance +
59→    $policies + $intents + $agent_sessions +
60→    $objectives + $behaviors
61→  );
62→};
63→
64→DEFINE FUNCTION OVERWRITE fn::project_entity_ids($ws: record<workspace>, $project: record<project>) {
65→  LET $features = (SELECT VALUE out FROM has_feature WHERE `in` = $project);
66→  LET $tasks = (SELECT VALUE out FROM has_task WHERE `in` IN $features);
67→  LET $belongs_project = (SELECT VALUE `in` FROM belongs_to WHERE out = $project);
68→  LET $belongs_feature = (SELECT VALUE `in` FROM belongs_to WHERE out IN $features);
69→  LET $identities = (SELECT VALUE `in` FROM member_of WHERE out = $ws);
70→  LET $provenance = (
71→    SELECT VALUE out FROM extraction_relation
72→    WHERE `in` IN (
73→      SELECT VALUE id FROM message
74→      WHERE conversation IN (
75→        SELECT VALUE id FROM conversation WHERE workspace = $ws
76→      )
77→    )
78→  );
79→  LET $all_tasks = array::distinct($tasks + $belongs_project + $belongs_feature);
80→  LET $project_tasks = (SELECT VALUE id FROM task WHERE id IN $all_tasks);
81→  LET $intents = (SELECT VALUE `in` FROM triggered_by WHERE out IN $project_tasks AND `in`.status NOT IN ['completed', 'vetoed', 'failed']);
82→  LET $objectives = (SELECT VALUE out FROM has_objective WHERE `in` = $project);
83→  RETURN array::distinct(
84→    [$project] + $features + $tasks +
85→    $belongs_project + $belongs_feature +
86→    $identities + $provenance + $intents +
87→    $objectives
88→  );
89→};
