  1→/**
  2→ * Objective CRUD Queries
  3→ *
  4→ * Pure database query functions for the objective table.
  5→ * All functions accept Surreal + RecordId params and return typed results.
  6→ * Embedding generation is handled by the caller using the existing pipeline.
  7→ */
  8→import { RecordId, type Surreal } from "surrealdb";
  9→
 10→// ---------------------------------------------------------------------------
 11→// Types
 12→// ---------------------------------------------------------------------------
 13→
 14→export type ObjectiveStatus = "draft" | "active" | "completed" | "archived" | "expired";
 15→export type ObjectivePriority = "low" | "medium" | "high" | "critical";
 16→
 17→export type SuccessCriterion = {
 18→  metric_name: string;
 19→  target_value: number;
 20→  current_value: number;
 21→  unit: string;
 22→};
 23→
 24→export type ObjectiveRecord = {
 25→  id: RecordId<"objective">;
 26→  title: string;
 27→  description?: string;
 28→  status: ObjectiveStatus;
 29→  priority: ObjectivePriority;
 30→  target_date?: string;
 31→  success_criteria: SuccessCriterion[];
 32→  workspace: RecordId<"workspace">;
 33→  source_message?: RecordId<"message">;
 34→  created_by?: RecordId<"identity">;
 35→  embedding?: number[];
 36→  created_at: string;
 37→  updated_at?: string;
 38→};
 39→
 40→export type CreateObjectiveParams = {
 41→  title: string;
 42→  description?: string;
 43→  status?: ObjectiveStatus;
 44→  priority?: ObjectivePriority;
 45→  target_date?: string;
 46→  success_criteria?: SuccessCriterion[];
 47→  source_message?: RecordId<"message">;
 48→  created_by?: RecordId<"identity">;
 49→  embedding?: number[];
 50→};
 51→
 52→// ---------------------------------------------------------------------------
 53→// Create
 54→// ---------------------------------------------------------------------------
 55→
 56→export async function createObjective(
 57→  surreal: Surreal,
 58→  workspaceId: string,
 59→  params: CreateObjectiveParams,
 60→): Promise<{ objectiveId: string }> {
 61→  const objectiveId = crypto.randomUUID();
 62→  const objectiveRecord = new RecordId("objective", objectiveId);
 63→  const workspaceRecord = new RecordId("workspace", workspaceId);
 64→
 65→  const content: Record<string, unknown> = {
 66→    title: params.title,
 67→    status: params.status ?? "active",
 68→    priority: params.priority ?? "medium",
 69→    success_criteria: params.success_criteria ?? [],
 70→    workspace: workspaceRecord,
 71→    created_at: new Date(),
 72→  };
 73→
 74→  if (params.description !== undefined) content.description = params.description;
 75→  if (params.target_date !== undefined) content.target_date = params.target_date;
 76→  if (params.source_message !== undefined) content.source_message = params.source_message;
 77→  if (params.created_by !== undefined) content.created_by = params.created_by;
 78→  if (params.embedding !== undefined) content.embedding = params.embedding;
 79→
 80→  await surreal.query(`CREATE $objective CONTENT $content;`, {
 81→    objective: objectiveRecord,
 82→    content,
 83→  });
 84→
 85→  return { objectiveId };
 86→}
 87→
 88→// ---------------------------------------------------------------------------
 89→// Read
 90→// ---------------------------------------------------------------------------
 91→
 92→export async function getObjective(
 93→  surreal: Surreal,
 94→  objectiveId: string,
 95→): Promise<ObjectiveRecord | undefined> {
 96→  const objectiveRecord = new RecordId("objective", objectiveId);
 97→  const rows = (await surreal.query(`SELECT * FROM $objective;`, {
 98→    objective: objectiveRecord,
 99→  })) as Array<ObjectiveRecord[]>;
100→  return rows[0]?.[0];
101→}
102→
103→// ---------------------------------------------------------------------------
104→// List
105→// ---------------------------------------------------------------------------
106→
107→export async function listObjectives(
108→  surreal: Surreal,
109→  workspaceId: string,
110→  status?: ObjectiveStatus,
111→): Promise<ObjectiveRecord[]> {
112→  const workspaceRecord = new RecordId("workspace", workspaceId);
113→
114→  const query = status
115→    ? `SELECT * FROM objective WHERE workspace = $ws AND status = $status ORDER BY created_at DESC;`
116→    : `SELECT * FROM objective WHERE workspace = $ws ORDER BY created_at DESC;`;
117→  const rows = (await surreal.query(query, { ws: workspaceRecord, status })) as Array<ObjectiveRecord[]>;
118→  return rows[0] ?? [];
119→}
120→
121→// ---------------------------------------------------------------------------
122→// Update Status
123→// ---------------------------------------------------------------------------
124→
125→export async function updateObjectiveStatus(
126→  surreal: Surreal,
127→  objectiveId: string,
128→  status: ObjectiveStatus,
129→): Promise<void> {
130→  const objectiveRecord = new RecordId("objective", objectiveId);
131→  await surreal.query(`UPDATE $objective SET status = $status, updated_at = time::now();`, {
132→    objective: objectiveRecord,
133→    status,
134→  });
135→}
136→
137→// ---------------------------------------------------------------------------
138→// Update Success Criteria
139→// ---------------------------------------------------------------------------
140→
141→export async function updateSuccessCriteria(
142→  surreal: Surreal,
143→  objectiveId: string,
144→  successCriteria: SuccessCriterion[],
145→): Promise<void> {
146→  const objectiveRecord = new RecordId("objective", objectiveId);
147→  await surreal.query(
148→    `UPDATE $objective SET success_criteria = $criteria, updated_at = time::now();`,
149→    { objective: objectiveRecord, criteria: successCriteria },
150→  );
151→}
152→
153→// ---------------------------------------------------------------------------
154→// Progress
155→// ---------------------------------------------------------------------------
156→
157→export type ObjectiveProgress = {
158→  objective_id: string;
159→  title: string;
160→  status: ObjectiveStatus;
161→  supporting_intent_count: number;
162→  success_criteria: SuccessCriterion[];
163→  target_date?: string;
164→  is_expired: boolean;
165→  is_unsupported: boolean;
166→};
167→
168→/**
169→ * Computes objective progress via graph traversal.
170→ *
171→ * - Supporting intent count: count(<-supports<-intent)
172→ * - Expiration: query-time check against target_date
173→ * - Unsupported: supporting_intent_count === 0
174→ */
175→export async function getObjectiveProgress(
176→  surreal: Surreal,
177→  objectiveId: string,
178→): Promise<ObjectiveProgress | undefined> {
179→  const objectiveRecord = new RecordId("objective", objectiveId);
180→
181→  // Single query: fetch objective + count supporting intents + expiration check
182→  const rows = (await surreal.query(
183→    `SELECT
184→       id,
185→       title,
186→       status,
187→       success_criteria,
188→       target_date,
189→       count(<-supports<-intent) AS supporting_intent_count,
190→       (target_date != NONE AND <datetime>target_date < time::now()) AS is_expired
191→     FROM $objective;`,
192→    { objective: objectiveRecord },
193→  )) as Array<Array<{
194→    id: RecordId<"objective">;
195→    title: string;
196→    status: ObjectiveStatus;
197→    success_criteria: SuccessCriterion[];
198→    target_date?: string;
199→    supporting_intent_count: number;
200→    is_expired: boolean;
201→  }>>;
202→
203→  const row = rows[0]?.[0];
204→  if (!row) return undefined;
205→
206→  return {
207→    objective_id: row.id.id as string,
208→    title: row.title,
209→    status: row.status,
210→    supporting_intent_count: row.supporting_intent_count,
211→    success_criteria: row.success_criteria,
212→    target_date: row.target_date,
213→    is_expired: row.is_expired,
214→    is_unsupported: row.supporting_intent_count === 0,
215→  };
216→}
217→
218→// ---------------------------------------------------------------------------
219→// Link to Project/Workspace
220→// ---------------------------------------------------------------------------
221→
222→export async function linkObjectiveToOwner(
223→  surreal: Surreal,
224→  ownerTable: "project" | "workspace",
225→  ownerId: string,
226→  objectiveId: string,
227→): Promise<void> {
228→  const ownerRecord = new RecordId(ownerTable, ownerId);
229→  const objectiveRecord = new RecordId("objective", objectiveId);
230→  await surreal.query(
231→    `RELATE $owner->has_objective->$objective SET added_at = time::now();`,
232→    { owner: ownerRecord, objective: objectiveRecord },
233→  );
234→}
