 98→// ---------------------------------------------------------------------------
 99→// Graph queries (pure data gathering)
100→// ---------------------------------------------------------------------------
101→
102→async function queryConfirmedDecisions(
103→  surreal: Surreal,
104→  workspaceRecord: RecordId<"workspace", string>,
105→): Promise<ConfirmedDecision[]> {
106→  const [rows] = await surreal.query<[ConfirmedDecision[]]>(
107→    `SELECT id, summary, rationale, created_at FROM decision
108→     WHERE workspace = $ws AND status = "confirmed"
109→     ORDER BY created_at DESC
110→     LIMIT 50;`,
111→    { ws: workspaceRecord },
112→  );
113→  return rows ?? [];
114→}
115→
116→async function queryCompletedTasks(
117→  surreal: Surreal,
118→  workspaceRecord: RecordId<"workspace", string>,
119→): Promise<CompletedTask[]> {
120→  const [rows] = await surreal.query<[CompletedTask[]]>(
121→    `SELECT id, title, description, updated_at FROM task
122→     WHERE workspace = $ws AND status IN ["completed", "done"]
123→     ORDER BY updated_at DESC
124→     LIMIT 50;`,
125→    { ws: workspaceRecord },
126→  );
127→  return rows ?? [];
128→}
129→
130→async function queryStaleBlockedTasks(
131→  surreal: Surreal,
132→  workspaceRecord: RecordId<"workspace", string>,
133→): Promise<StaleBlockedTask[]> {
134→  const thresholdDate = new Date(
135→    Date.now() - STALE_BLOCKED_THRESHOLD_DAYS * 24 * 60 * 60 * 1000,
136→  );
137→
138→  const [rows] = await surreal.query<
139→    [Array<{ id: RecordId<"task">; title: string; description?: string; updated_at: string }>]
140→  >(
141→    `SELECT id, title, description, updated_at FROM task
142→     WHERE workspace = $ws
143→       AND status = "blocked"
144→       AND updated_at < $threshold
145→     ORDER BY updated_at ASC
146→     LIMIT 50;`,
147→    { ws: workspaceRecord, threshold: thresholdDate },
148→  );
149→
150→  return (rows ?? []).map((row) => {
151→    const updatedAt = new Date(row.updated_at);
152→    const daysBlocked = Math.floor(
153→      (Date.now() - updatedAt.getTime()) / (24 * 60 * 60 * 1000),
154→    );
155→    return { ...row, daysBlocked };
156→  });
157→}
158→
159→async function queryStatusDriftTasks(
160→  surreal: Surreal,
161→  workspaceRecord: RecordId<"workspace", string>,
162→): Promise<StatusDriftTask[]> {
163→  // Two-step approach: first find completed tasks with dependencies,
164→  // then filter for incomplete dependencies in application code
165→  const [rows] = await surreal.query<[Array<{
166→    id: RecordId<"task">;
167→    title: string;
168→    status: string;
169→    dep_ids: RecordId<"task">[];
170→    dep_titles: string[];
171→    dep_statuses: string[];
172→  }>]>(
173→    `SELECT
174→       id, title, status,
175→       ->depends_on->task.id AS dep_ids,
176→       ->depends_on->task.title AS dep_titles,
177→       ->depends_on->task.status AS dep_statuses
178→     FROM task
179→     WHERE workspace = $ws
180→       AND status IN ["completed", "done"]
181→       AND array::len(->depends_on->task) > 0
182→     LIMIT 50;`,
183→    { ws: workspaceRecord },
184→  );
185→
186→  return (rows ?? []).flatMap((row) => {
187→    const depIds = row.dep_ids ?? [];
188→    const depTitles = row.dep_titles ?? [];
189→    const depStatuses = row.dep_statuses ?? [];
190→
191→    const drifts: StatusDriftTask[] = [];
192→    for (let i = 0; i < depIds.length; i++) {
193→      const depStatus = depStatuses[i];
194→      if (depStatus !== "completed" && depStatus !== "done") {
195→        drifts.push({
196→          id: row.id,
197→          title: row.title,
198→          status: row.status,
199→          dependency: {
200→            id: depIds[i],

200→            id: depIds[i],
201→            title: depTitles[i],
202→            status: depStatus,
203→          },
204→        });
205→      }
206→    }
207→    return drifts;
208→  });
209→}
