211→// ---------------------------------------------------------------------------
212→// Entity-level deduplication query
213→// ---------------------------------------------------------------------------
214→
215→/**
216→ * Queries existing open observer observations linked to a specific entity.
217→ * Used for entity-level dedup -- if the observer already has an open observation
218→ * on this entity, we skip creating another.
219→ */
220→// Static query map: one pre-built query string per allowed table, eliminating
221→// dynamic interpolation at the call site (prevents SurrealQL injection).
222→const OBSERVER_DEDUP_QUERIES: Record<string, string> = Object.fromEntries(
223→  ["project", "feature", "task", "decision", "question", "intent", "git_commit", "observation", "objective"].map(
224→    (table) => [
225→      table,
226→      `SELECT text, severity, status FROM observation
227→       WHERE workspace = $ws
228→         AND source_agent = "observer_agent"
229→         AND status IN ["open", "acknowledged"]
230→         AND ->observes->${table}.id CONTAINS $entity
231→       LIMIT 20;`,
232→    ],
233→  ),
234→);
235→
236→export async function queryExistingObserverObservationsForEntity(
237→  surreal: Surreal,
238→  workspaceRecord: RecordId<"workspace", string>,
239→  entityRecord: RecordId<string, string>,
240→): Promise<Array<{ text: string; severity: string; status: string }>> {
241→  const query = OBSERVER_DEDUP_QUERIES[entityRecord.table.name];
242→  if (!query) {
243→    throw new Error(`Invalid entity table for observer dedup query: ${entityRecord.table.name}`);
244→  }
245→
246→  const [rows] = await surreal.query<[Array<{ text: string; severity: string; status: string }>]>(
247→    query,
248→    { ws: workspaceRecord, entity: entityRecord },
249→  );
250→  return rows ?? [];
251→}
252→
253→// ---------------------------------------------------------------------------
254→// Deduplication
255→// ---------------------------------------------------------------------------
256→
257→type ExistingObservation = {
258→  text: string;
259→  severity: string;
260→  status: string;
261→};
262→
263→function isAlreadyObserved(
264→  existingObservations: ExistingObservation[],
265→  newText: string,
266→  entityId?: string,
267→): boolean {
268→  const normalizedNew = newText.toLowerCase();
269→
270→  return existingObservations.some((obs) => {
271→    if (obs.status === "resolved") return false;
272→
273→    // When entity ID is available, require it to appear in the existing text
274→    // so observations about different entities are never considered duplicates
275→    if (entityId && !obs.text.toLowerCase().includes(entityId.toLowerCase())) {
276→      return false;
277→    }
278→
279→    const normalizedExisting = obs.text.toLowerCase();
280→    // Check if the core issue is already covered using a meaningful prefix
281→    const prefixLen = Math.min(80, normalizedNew.length);
282→    return (
283→      normalizedExisting.includes(normalizedNew.slice(0, prefixLen)) ||
284→      normalizedNew.includes(normalizedExisting.slice(0, prefixLen))
285→    );
286→  });
287→}
