  1→/**
  2→ * Behavior Scorer -- Pure Functions
  3→ *
  4→ * Maps raw telemetry data to normalized 0-1 scores per metric type.
  5→ * This module has ZERO IO imports. It is pure data transformation only.
  6→ *
  7→ * Each metric type has:
  8→ *   1. A discriminated union type for its telemetry shape
  9→ *   2. A scorer function: telemetry -> ScorerResult
 10→ *   3. A validation function for runtime shape checking
 11→ */
 12→
 13→// ---------------------------------------------------------------------------
 14→// Result Types
 15→// ---------------------------------------------------------------------------
 16→
 17→export type ScorerResult =
 18→  | { success: true; score: number }
 19→  | { success: false; reason: string };
 20→
 21→export type ValidationResult =
 22→  | { valid: true }
 23→  | { valid: false; reason: string };
 24→
 25→// ---------------------------------------------------------------------------
 26→// Telemetry Types (Discriminated Union)
 27→// ---------------------------------------------------------------------------
 28→
 29→export type TddTelemetry = {
 30→  metric_type: "TDD_Adherence";
 31→  files_changed: number;
 32→  test_files_changed: number;
 33→  coverage_delta?: number;
 34→};
 35→
 36→export type SecurityTelemetry = {
 37→  metric_type: "Security_First";
 38→  cve_advisories_in_context: number;
 39→  cve_advisories_addressed: number;
 40→};
 41→
 42→export type BehaviorTelemetry = TddTelemetry | SecurityTelemetry;
 43→
 44→// ---------------------------------------------------------------------------
 45→// Known Metric Types
 46→// ---------------------------------------------------------------------------
 47→
 48→export const KNOWN_METRIC_TYPES = [
 49→  "TDD_Adherence",
 50→  "Security_First",
 51→  "Conciseness",
 52→  "Review_Responsiveness",
 53→  "Documentation_Quality",
 54→] as const;
 55→
 56→export type MetricType = (typeof KNOWN_METRIC_TYPES)[number];
 57→
 58→// ---------------------------------------------------------------------------
 59→// Scorer Functions
 60→// ---------------------------------------------------------------------------
 61→
 62→function clampScore(value: number): number {
 63→  return Math.min(1.0, Math.max(0.0, value));
 64→}
 65→
 66→/**
 67→ * Scores TDD adherence as the ratio of test files changed to total files changed.
 68→ * Score is clamped to [0.0, 1.0].
 69→ */
 70→export function scoreTddAdherence(telemetry: TddTelemetry): ScorerResult {
 71→  const { files_changed, test_files_changed } = telemetry;
 72→
 73→  if (files_changed === 0) {
 74→    return { success: true, score: 0.0 };
 75→  }
 76→
 77→  return { success: true, score: clampScore(test_files_changed / files_changed) };
 78→}
 79→
 80→/**
 81→ * Scores security-first behavior as the ratio of addressed CVE advisories
 82→ * to total advisories in context. Returns 1.0 when no advisories exist.
 83→ */
 84→export function scoreSecurityFirst(telemetry: SecurityTelemetry): ScorerResult {
 85→  const { cve_advisories_in_context, cve_advisories_addressed } = telemetry;
 86→
 87→  if (cve_advisories_in_context === 0) {
 88→    return { success: true, score: 1.0 };
 89→  }
 90→
 91→  return { success: true, score: clampScore(cve_advisories_addressed / cve_advisories_in_context) };
 92→}
 93→
 94→// ---------------------------------------------------------------------------
 95→// Telemetry Shape Validation
 96→// ---------------------------------------------------------------------------
 97→
 98→const REQUIRED_FIELDS: Record<string, string[]> = {
 99→  TDD_Adherence: ["files_changed", "test_files_changed"],
100→  Security_First: ["cve_advisories_in_context", "cve_advisories_addressed"],
101→};
102→
103→/**
104→ * Validates that raw telemetry data has the required fields for a metric type.
105→ * Pure runtime validation -- no IO, no schema lookups.
106→ */
107→export function validateTelemetryShape(
108→  metricType: string,
109→  telemetry: Record<string, unknown>,
110→): ValidationResult {
111→  const requiredFields = REQUIRED_FIELDS[metricType];
112→
113→  if (!requiredFields) {
114→    const sanitizedType = String(metricType).slice(0, 100).replace(/[^\w_-]/g, "_");
115→    return {
116→      valid: false,
117→      reason: `Unknown metric type: ${sanitizedType}. Known types: ${Object.keys(REQUIRED_FIELDS).join(", ")}`,
118→    };
119→  }
120→
121→  const missingFields = requiredFields.filter(
122→    (field) => telemetry[field] === undefined,
123→  );
124→
125→  if (missingFields.length > 0) {
126→    return {
127→      valid: false,
128→      reason: `Missing required fields for ${metricType}: ${missingFields.join(", ")}`,
129→    };
130→  }
131→
132→  const nonNumericFields = requiredFields.filter(
133→    (field) => typeof telemetry[field] !== "number",
134→  );
135→
136→  if (nonNumericFields.length > 0) {
137→    return {
138→      valid: false,
139→      reason: `Non-numeric values for ${metricType}: ${nonNumericFields.join(", ")}`,
140→    };
141→  }
142→
143→  return { valid: true };
144→}
145→
146→// ---------------------------------------------------------------------------
147→// Score Dispatcher
148→// ---------------------------------------------------------------------------
149→
150→/**
151→ * Scores telemetry for any known metric type. Validates shape, then delegates
152→ * to the appropriate scorer function.
153→ */
154→export function scoreTelemetry(
155→  metricType: string,
156→  telemetry: Record<string, unknown>,
157→): ScorerResult {
158→  const validation = validateTelemetryShape(metricType, telemetry);
159→  if (!validation.valid) {
160→    return { success: false, reason: validation.reason };
161→  }
162→
163→  switch (metricType) {
164→    case "TDD_Adherence":
165→      return scoreTddAdherence({
166→        metric_type: "TDD_Adherence",
167→        files_changed: telemetry.files_changed as number,
168→        test_files_changed: telemetry.test_files_changed as number,
169→        coverage_delta: telemetry.coverage_delta as number | undefined,
170→      });
171→    case "Security_First":
172→      return scoreSecurityFirst({
173→        metric_type: "Security_First",
174→        cve_advisories_in_context: telemetry.cve_advisories_in_context as number,
175→        cve_advisories_addressed: telemetry.cve_advisories_addressed as number,
176→      });
177→    default:
178→      return { success: false, reason: `No scorer implemented for metric type: ${String(metricType).slice(0, 100).replace(/[^\w_-]/g, "_")}` };
179→  }
180→}
181→

  1→/**
  2→ * Behavior Trend Analysis -- Pure Functions
  3→ *
  4→ * Detects behavioral patterns from score arrays: drift (consecutive
  5→ * below-threshold), improvement (rising scores crossing threshold),
  6→ * flat-line (stagnation), and stable (healthy above-threshold).
  7→ *
  8→ * This module has ZERO IO imports. It is pure data transformation only.
  9→ * Threshold and streak length are parameters, not hardcoded.
 10→ */
 11→
 12→// ---------------------------------------------------------------------------
 13→// Types
 14→// ---------------------------------------------------------------------------
 15→
 16→export type ScorePoint = {
 17→  score: number;
 18→  timestamp: string;
 19→};
 20→
 21→export type TrendPattern =
 22→  | "drift"
 23→  | "improving"
 24→  | "flat"
 25→  | "stable"
 26→  | "insufficient_data";
 27→
 28→export type TrendResult = {
 29→  pattern: TrendPattern;
 30→  belowThreshold: boolean;
 31→  streakLength: number;
 32→};
 33→
 34→export type TrendOptions = {
 35→  threshold?: number;
 36→  minStreakLength?: number;
 37→  flatTolerance?: number;
 38→};
 39→
 40→export type DriftResult = {
 41→  detected: boolean;
 42→  streakLength: number;
 43→};
 44→
 45→export type ImprovementResult = {
 46→  detected: boolean;
 47→};
 48→
 49→export type FlatLineResult = {
 50→  detected: boolean;
 51→  belowThreshold: boolean;
 52→};
 53→
 54→// ---------------------------------------------------------------------------
 55→// Default Parameters
 56→// ---------------------------------------------------------------------------
 57→
 58→const DEFAULT_THRESHOLD = 0.70;
 59→const DEFAULT_MIN_STREAK_LENGTH = 3;
 60→const DEFAULT_FLAT_TOLERANCE = 0.10;
 61→
 62→// ---------------------------------------------------------------------------
 63→// Drift Detection
 64→// ---------------------------------------------------------------------------
 65→
 66→/**
 67→ * Detects consecutive below-threshold scores from the end of the array.
 68→ * Returns the trailing streak length. A streak of >= minStreakLength
 69→ * indicates behavioral drift.
 70→ */
 71→export function detectDriftStreak(
 72→  points: ScorePoint[],
 73→  threshold: number,
 74→  minStreakLength: number,
 75→): DriftResult {
 76→  if (points.length === 0) {
 77→    return { detected: false, streakLength: 0 };
 78→  }
 79→
 80→  // Count trailing consecutive below-threshold scores (from end)
 81→  let streakLength = 0;
 82→  for (let i = points.length - 1; i >= 0; i--) {
 83→    if (points[i].score < threshold) {
 84→      streakLength++;
 85→    } else {
 86→      break;
 87→    }
 88→  }
 89→
 90→  return {
 91→    detected: streakLength >= minStreakLength,
 92→    streakLength,
 93→  };
 94→}
 95→
 96→// ---------------------------------------------------------------------------
 97→// Improvement Detection
 98→// ---------------------------------------------------------------------------
 99→
100→/**
101→ * Detects improving trend using simple linear slope. An improving trend
102→ * requires a positive slope AND the latest score at or above threshold.
103→ */
104→export function detectImprovement(
105→  points: ScorePoint[],
106→  threshold: number,
107→): ImprovementResult {
108→  if (points.length < 2) {
109→    return { detected: false };
110→  }
111→
112→  const scores = points.map((p) => p.score);
113→  const slope = computeSlope(scores);
114→  const latestScore = scores[scores.length - 1];
115→  const firstScore = scores[0];
116→
117→  // Improvement requires: positive slope, latest above threshold,
118→  // and started below threshold (otherwise it is just stable above).
119→  return {
120→    detected: slope > 0 && latestScore >= threshold && firstScore < threshold,
121→  };
122→}
123→
124→// ---------------------------------------------------------------------------
125→// Flat-Line Detection
126→// ---------------------------------------------------------------------------
127→
128→/**
129→ * Detects flat-line pattern where score variance stays within tolerance.
130→ * Indicates stagnation -- especially concerning when below threshold
131→ * (ineffective learning).
132→ */
133→export function detectFlatLine(
134→  points: ScorePoint[],
135→  threshold: number,
136→  flatTolerance: number,
137→): FlatLineResult {
138→  if (points.length < 2) {
139→    return { detected: false, belowThreshold: false };
140→  }
141→
142→  const scores = points.map((p) => p.score);
143→  const min = Math.min(...scores);
144→  const max = Math.max(...scores);
145→  const range = max - min;
146→  const isFlat = range < flatTolerance;
147→
148→  if (!isFlat) {
149→    return { detected: false, belowThreshold: false };
150→  }
151→
152→  const average = scores.reduce((sum, s) => sum + s, 0) / scores.length;
153→  return {
154→    detected: true,
155→    belowThreshold: average < threshold,
156→  };
157→}
158→
159→// ---------------------------------------------------------------------------
160→// Top-Level Trend Classifier
161→// ---------------------------------------------------------------------------
162→
163→/**
164→ * Analyzes a time-ordered score array (oldest first) and classifies
165→ * the behavioral trend. Priority order:
166→ *   1. insufficient_data (fewer than minStreakLength points)
167→ *   2. improving (positive slope, latest above threshold)
168→ *   3. drift (trailing below-threshold streak >= minStreakLength)
169→ *   4. flat (low variance, may be below threshold)
170→ *   5. stable (above threshold, not flat)
171→ */
172→export function analyzeTrend(
173→  points: ScorePoint[],
174→  options?: TrendOptions,
175→): TrendResult {
176→  const threshold = options?.threshold ?? DEFAULT_THRESHOLD;
177→  const minStreakLength = options?.minStreakLength ?? DEFAULT_MIN_STREAK_LENGTH;
178→  const flatTolerance = options?.flatTolerance ?? DEFAULT_FLAT_TOLERANCE;
179→
180→  // 1. Insufficient data
181→  if (points.length < minStreakLength) {
182→    return {
183→      pattern: "insufficient_data",
184→      belowThreshold: false,
185→      streakLength: 0,
186→    };
187→  }
188→
189→  // 2. Check for improvement (positive slope, crossed threshold from below)
190→  const improvement = detectImprovement(points, threshold);
191→  if (improvement.detected) {
192→    return {
193→      pattern: "improving",
194→      belowThreshold: false,
195→      streakLength: 0,
196→    };
197→  }
198→
199→  // 3. Check for drift vs flat-line (both involve below-threshold scores)
200→  const drift = detectDriftStreak(points, threshold, minStreakLength);
201→  const flatLine = detectFlatLine(points, threshold, flatTolerance);
202→
203→  // When the history is flat, below threshold, and has more data points
204→  // than the minimum streak, classify as "flat" (established stagnation /
205→  // ineffective learning). With exactly minStreakLength points, prefer
206→  // "drift" (newly detected decline needing intervention).
207→  if (
208→    flatLine.detected &&
209→    flatLine.belowThreshold &&
210→    points.length > minStreakLength
211→  ) {
212→    return {
213→      pattern: "flat",
214→      belowThreshold: true,
215→      streakLength: 0,
216→    };
217→  }
218→
219→  if (drift.detected) {
220→    return {
221→      pattern: "drift",
222→      belowThreshold: true,
223→      streakLength: drift.streakLength,
224→    };
225→  }
226→
227→  if (flatLine.detected && flatLine.belowThreshold) {
228→    return {
229→      pattern: "flat",
230→      belowThreshold: true,
231→      streakLength: 0,
232→    };
233→  }
234→
235→  // 5. Default: stable (above threshold, no concerning pattern)
236→  const latestScore = points[points.length - 1].score;
237→  return {
238→    pattern: "stable",
239→    belowThreshold: latestScore < threshold,
240→    streakLength: 0,
241→  };
242→}
243→
244→// ---------------------------------------------------------------------------
245→// Internal Helpers
246→// ---------------------------------------------------------------------------
247→
248→/**
249→ * Computes simple linear slope over score values using least-squares.
250→ * Positive = improving, negative = declining, near-zero = flat.
251→ */
252→function computeSlope(scores: number[]): number {
253→  const n = scores.length;
254→  if (n < 2) return 0;
255→
256→  // x values are 0, 1, 2, ... (index-based)
257→  const sumX = (n * (n - 1)) / 2;
258→  const sumY = scores.reduce((sum, s) => sum + s, 0);
259→  const sumXY = scores.reduce((sum, s, i) => sum + i * s, 0);
260→  const sumXX = (n * (n - 1) * (2 * n - 1)) / 6;
261→
262→  return (n * sumXY - sumX * sumY) / (n * sumXX - sumX * sumX);
263→}
264→

  1→/**
  2→ * Behavior CRUD Queries
  3→ *
  4→ * Driven port implementations for behavior record persistence.
  5→ * All queries use RecordId objects per project convention.
  6→ * Behavior records are append-only -- no UPDATE queries.
  7→ */
  8→import { RecordId, type Surreal } from "surrealdb";
  9→import type { IntentEvaluationContext } from "../policy/types";
 10→
 11→// ---------------------------------------------------------------------------
 12→// Types
 13→// ---------------------------------------------------------------------------
 14→
 15→export type BehaviorInput = {
 16→  metricType: string;
 17→  score: number;
 18→  sourceTelemetry: Record<string, unknown>;
 19→  workspaceId: string;
 20→  sessionId?: string;
 21→};
 22→
 23→export type BehaviorRow = {
 24→  id: RecordId<"behavior">;
 25→  metric_type: string;
 26→  score: number;
 27→  source_telemetry: Record<string, unknown>;
 28→  workspace: RecordId<"workspace">;
 29→  session?: RecordId<"agent_session">;
 30→  created_at: string;
 31→};
 32→
 33→export type ExhibitsEdgeRow = {
 34→  id: RecordId<"exhibits">;
 35→  in: RecordId<"identity">;
 36→  out: RecordId<"behavior">;
 37→  created_at: string;
 38→};
 39→
 40→// ---------------------------------------------------------------------------
 41→// Create Behavior Record (append-only)
 42→// ---------------------------------------------------------------------------
 43→
 44→/**
 45→ * Creates a behavior record and the exhibits edge linking identity to behavior.
 46→ * Append-only: never updates existing records.
 47→ */
 48→export async function createBehavior(
 49→  surreal: Surreal,
 50→  identityId: string,
 51→  input: BehaviorInput,
 52→): Promise<{ behaviorId: string }> {
 53→  const behaviorId = `beh-${crypto.randomUUID()}`;
 54→  const behaviorRecord = new RecordId("behavior", behaviorId);
 55→  const workspaceRecord = new RecordId("workspace", input.workspaceId);
 56→  const identityRecord = new RecordId("identity", identityId);
 57→
 58→  const content: Record<string, unknown> = {
 59→    metric_type: input.metricType,
 60→    score: input.score,
 61→    source_telemetry: input.sourceTelemetry,
 62→    workspace: workspaceRecord,
 63→    created_at: new Date(),
 64→  };
 65→
 66→  if (input.sessionId) {
 67→    content.session = new RecordId("agent_session", input.sessionId);
 68→  }
 69→
 70→  await surreal.query(`CREATE $behavior CONTENT $content;`, {
 71→    behavior: behaviorRecord,
 72→    content,
 73→  });
 74→
 75→  // Create exhibits edge: identity ->exhibits-> behavior
 76→  await surreal.query(
 77→    `RELATE $identity->exhibits->$behavior SET created_at = time::now();`,
 78→    { identity: identityRecord, behavior: behaviorRecord },
 79→  );
 80→
 81→  return { behaviorId };
 82→}
 83→
 84→// ---------------------------------------------------------------------------
 85→// Query Behavior Records
 86→// ---------------------------------------------------------------------------
 87→
 88→/**
 89→ * Lists behavior records for an identity, optionally filtered by metric type.
 90→ * Returns records ordered by created_at DESC (most recent first).
 91→ */
 92→export async function listBehaviors(
 93→  surreal: Surreal,
 94→  identityId: string,
 95→  metricType?: string,
 96→): Promise<BehaviorRow[]> {
 97→  const identityRecord = new RecordId("identity", identityId);
 98→
 99→  // Traverse exhibits edges from identity to behavior
100→  const edgeRows = (await surreal.query(
101→    `SELECT ->exhibits->behavior AS behaviors FROM $identity;`,
102→    { identity: identityRecord },
103→  )) as Array<Array<{ behaviors: RecordId[] }>>;
104→
105→  const behaviorIds = edgeRows[0]?.[0]?.behaviors ?? [];
106→  if (behaviorIds.length === 0) return [];
107→
108→  const query = metricType
109→    ? `SELECT * FROM behavior WHERE id IN $ids AND metric_type = $mt ORDER BY created_at DESC;`
110→    : `SELECT * FROM behavior WHERE id IN $ids ORDER BY created_at DESC;`;
111→  const rows = (await surreal.query(query, { ids: behaviorIds, mt: metricType })) as Array<BehaviorRow[]>;
112→  return rows[0] ?? [];
113→}
114→
115→/**
116→ * Gets the latest behavior score for an identity and metric type.
117→ */
118→export async function getLatestScore(
119→  surreal: Surreal,
120→  identityId: string,
121→  metricType: string,
122→): Promise<number | undefined> {
123→  const records = await listBehaviors(surreal, identityId, metricType);
124→  return records[0]?.score;
125→}
126→
127→/**
128→ * Gets the latest score per unique metric_type for an identity.
129→ * Returns a map of metric_type -> score, using the most recent record per metric.
130→ * Used for context enrichment before policy gate evaluation.
131→ */
132→export async function getLatestBehaviorScores(
133→  surreal: Surreal,
134→  identityId: string,
135→): Promise<Record<string, number>> {
136→  const allRecords = await listBehaviors(surreal, identityId);
137→
138→  // Records are already sorted by created_at DESC from listBehaviors.
139→  // Take the first (most recent) score per metric_type.
140→  const scores: Record<string, number> = {};
141→  for (const record of allRecords) {
142→    if (!(record.metric_type in scores)) {
143→      scores[record.metric_type] = record.score;
144→    }
145→  }
146→
147→  return scores;
148→}
149→
150→/**
151→ * Enriches an IntentEvaluationContext with behavior scores for an identity.
152→ * Context enrichment happens before policy gate evaluation, not inside it.
153→ * Returns a new context object (immutable -- does not mutate the input).
154→ */
155→export async function enrichBehaviorScores(
156→  surreal: Surreal,
157→  identityId: string,
158→  context: IntentEvaluationContext,
159→): Promise<IntentEvaluationContext> {
160→  const scores = await getLatestBehaviorScores(surreal, identityId);
161→  return { ...context, behavior_scores: scores };
162→}
163→
164→/**
165→ * Lists behavior records for a workspace, optionally filtered by metric type.
166→ */
167→export async function listWorkspaceBehaviors(
168→  surreal: Surreal,
169→  workspaceId: string,
170→  metricType?: string,
171→  limit = 50,
172→): Promise<BehaviorRow[]> {
173→  const workspaceRecord = new RecordId("workspace", workspaceId);
174→
175→  const query = metricType
176→    ? `SELECT * FROM behavior WHERE workspace = $ws AND metric_type = $mt ORDER BY created_at DESC LIMIT $limit;`
177→    : `SELECT * FROM behavior WHERE workspace = $ws ORDER BY created_at DESC LIMIT $limit;`;
178→  const rows = (await surreal.query(query, { ws: workspaceRecord, mt: metricType, limit })) as Array<BehaviorRow[]>;
179→  return rows[0] ?? [];
180→}
181→

 1→/**
 2→ * Behavior HTTP Route Handlers
 3→ *
 4→ * Thin composition layer: parses HTTP requests, delegates to query functions,
 5→ * returns JSON responses. No domain logic lives here.
 6→ */
 7→import { logError } from "../http/observability";
 8→import { jsonError, jsonResponse } from "../http/response";
 9→import type { ServerDependencies } from "../runtime/types";
10→import {
11→  listWorkspaceBehaviors,
12→  listBehaviors,
13→  type BehaviorRow,
14→} from "./queries";
15→
16→// ---------------------------------------------------------------------------
17→// Response serialization (pure)
18→// ---------------------------------------------------------------------------
19→
20→function serializeBehavior(record: BehaviorRow) {
21→  return {
22→    id: record.id.id as string,
23→    metric_type: record.metric_type,
24→    score: record.score,
25→    source_telemetry: record.source_telemetry,
26→    workspace_id: record.workspace.id as string,
27→    ...(record.session ? { session_id: record.session.id as string } : {}),
28→    created_at: record.created_at,
29→  };
30→}
31→
32→// ---------------------------------------------------------------------------
33→// Route handler factory
34→// ---------------------------------------------------------------------------
35→
36→export function createBehaviorRouteHandlers(deps: ServerDependencies) {
37→  return {
38→    handleList: (workspaceId: string, request: Request) =>
39→      handleListBehaviors(deps, workspaceId, request),
40→  };
41→}
42→
43→// ---------------------------------------------------------------------------
44→// GET /api/workspaces/:workspaceId/behaviors
45→// ---------------------------------------------------------------------------
46→
47→async function handleListBehaviors(
48→  deps: ServerDependencies,
49→  workspaceId: string,
50→  request: Request,
51→): Promise<Response> {
52→  try {
53→    const url = new URL(request.url);
54→    const metricType = url.searchParams.get("metric_type") ?? undefined;
55→    const identityId = url.searchParams.get("identity_id") ?? undefined;
56→
57→    let records: BehaviorRow[];
58→
59→    if (identityId) {
60→      // Query by identity traversing exhibits edges
61→      records = await listBehaviors(deps.surreal, identityId, metricType);
62→      // Filter to workspace scope
63→      records = records.filter((r) => (r.workspace.id as string) === workspaceId);
64→    } else {
65→      // Query by workspace directly
66→      records = await listWorkspaceBehaviors(deps.surreal, workspaceId, metricType);
67→    }
68→
69→    return jsonResponse({
70→      behaviors: records.map(serializeBehavior),
71→    }, 200);
72→  } catch (error) {
73→    logError("behavior.list.failed", "Failed to list behaviors", error, { workspaceId });
74→    return jsonError("failed to list behaviors", 500);
75→  }
76→}
77→

  1→/**
  2→ * Objective CRUD Queries
  3→ *
  4→ * Pure database query functions for the objective table.
  5→ * All functions accept Surreal + RecordId params and return typed results.
  6→ * Embedding generation is handled by the caller using the existing pipeline.
  7→ */
  8→import { RecordId, type Surreal } from "surrealdb";
  9→
 10→// ---------------------------------------------------------------------------
 11→// Types
 12→// ---------------------------------------------------------------------------
 13→
 14→export type ObjectiveStatus = "draft" | "active" | "completed" | "archived" | "expired";
 15→export type ObjectivePriority = "low" | "medium" | "high" | "critical";
 16→
 17→export type SuccessCriterion = {
 18→  metric_name: string;
 19→  target_value: number;
 20→  current_value: number;
 21→  unit: string;
 22→};
 23→
 24→export type ObjectiveRecord = {
 25→  id: RecordId<"objective">;
 26→  title: string;
 27→  description?: string;
 28→  status: ObjectiveStatus;
