 58→  workspaceId: string,
 59→  params: CreateObjectiveParams,
 60→): Promise<{ objectiveId: string }> {
 61→  const objectiveId = crypto.randomUUID();
 62→  const objectiveRecord = new RecordId("objective", objectiveId);
 63→  const workspaceRecord = new RecordId("workspace", workspaceId);
 64→
 65→  const content: Record<string, unknown> = {
 66→    title: params.title,
 67→    status: params.status ?? "active",
 68→    priority: params.priority ?? "medium",
 69→    success_criteria: params.success_criteria ?? [],
 70→    workspace: workspaceRecord,
 71→    created_at: new Date(),
 72→  };
 73→
 74→  if (params.description !== undefined) content.description = params.description;
 75→  if (params.target_date !== undefined) content.target_date = params.target_date;
 76→  if (params.source_message !== undefined) content.source_message = params.source_message;
 77→  if (params.created_by !== undefined) content.created_by = params.created_by;
 78→  if (params.embedding !== undefined) content.embedding = params.embedding;
 79→
 80→  await surreal.query(`CREATE $objective CONTENT $content;`, {
 81→    objective: objectiveRecord,
 82→    content,
 83→  });
 84→
 85→  return { objectiveId };
