157→export type ObjectiveProgress = {
158→  objective_id: string;
159→  title: string;
160→  status: ObjectiveStatus;
161→  supporting_intent_count: number;
162→  success_criteria: SuccessCriterion[];
163→  target_date?: string;
164→  is_expired: boolean;
165→  is_unsupported: boolean;
166→};
167→
168→/**
169→ * Computes objective progress via graph traversal.
170→ *
171→ * - Supporting intent count: count(<-supports<-intent)
172→ * - Expiration: query-time check against target_date
173→ * - Unsupported: supporting_intent_count === 0
174→ */
175→export async function getObjectiveProgress(
176→  surreal: Surreal,
177→  objectiveId: string,
178→): Promise<ObjectiveProgress | undefined> {
179→  const objectiveRecord = new RecordId("objective", objectiveId);
180→
181→  // Single query: fetch objective + count supporting intents + expiration check
182→  const rows = (await surreal.query(
183→    `SELECT
184→       id,
185→       title,
186→       status,
187→       success_criteria,
188→       target_date,
189→       count(<-supports<-intent) AS supporting_intent_count,
190→       (target_date != NONE AND <datetime>target_date < time::now()) AS is_expired
191→     FROM $objective;`,
192→    { objective: objectiveRecord },
193→  )) as Array<Array<{
194→    id: RecordId<"objective">;
195→    title: string;
196→    status: ObjectiveStatus;
197→    success_criteria: SuccessCriterion[];
198→    target_date?: string;
199→    supporting_intent_count: number;
200→    is_expired: boolean;
201→  }>>;
202→
203→  const row = rows[0]?.[0];
204→  if (!row) return undefined;
205→
206→  return {
207→    objective_id: row.id.id as string,
208→    title: row.title,
209→    status: row.status,
210→    supporting_intent_count: row.supporting_intent_count,
211→    success_criteria: row.success_criteria,
212→    target_date: row.target_date,
213→    is_expired: row.is_expired,
214→    is_unsupported: row.supporting_intent_count === 0,
215→  };
216→}
