 35→export function loadServerConfig(): ServerConfig {
 36→  const openRouterApiKey = requireEnv("OPENROUTER_API_KEY");
 37→
 38→  const extractionStoreThreshold = parseUnitInterval(
 39→    requireEnv("EXTRACTION_STORE_THRESHOLD"),
 40→    "EXTRACTION_STORE_THRESHOLD",
 41→  );
 42→
 43→  const extractionDisplayThreshold = parseUnitInterval(
 44→    requireEnv("EXTRACTION_DISPLAY_THRESHOLD"),
 45→    "EXTRACTION_DISPLAY_THRESHOLD",
 46→  );
 47→
 48→  if (extractionDisplayThreshold < extractionStoreThreshold) {
 49→    throw new Error("EXTRACTION_DISPLAY_THRESHOLD must be greater than or equal to EXTRACTION_STORE_THRESHOLD");
 50→  }
 51→
 52→  const chatAgentModelId = requireEnv("CHAT_AGENT_MODEL");
 53→  const extractionModelId = requireEnv("EXTRACTION_MODEL");
 54→  const pmAgentModelId = Bun.env.PM_AGENT_MODEL && Bun.env.PM_AGENT_MODEL.trim().length > 0
 55→    ? Bun.env.PM_AGENT_MODEL.trim()
 56→    : extractionModelId;
 57→  const analyticsAgentModelId = requireEnv("ANALYTICS_MODEL");
 58→  const embeddingModelId = requireEnv("OPENROUTER_EMBEDDING_MODEL");
 59→  const embeddingDimension = parsePositiveInteger(requireEnv("EMBEDDING_DIMENSION"), "EMBEDDING_DIMENSION");
 60→
 61→  const surrealUrl = requireEnv("SURREAL_URL");
 62→  const surrealUsername = requireEnv("SURREAL_USERNAME");
 63→  const surrealPassword = requireEnv("SURREAL_PASSWORD");
 64→  const surrealNamespace = requireEnv("SURREAL_NAMESPACE");
 65→  const surrealDatabase = requireEnv("SURREAL_DATABASE");
 66→
 67→  const port = parsePositiveInteger(requireEnv("PORT"), "PORT");
 68→  const observerModelId = Bun.env.OBSERVER_MODEL && Bun.env.OBSERVER_MODEL.trim().length > 0
 69→    ? Bun.env.OBSERVER_MODEL.trim()
 70→    : undefined;
 71→  const githubWebhookSecret = Bun.env.GITHUB_WEBHOOK_SECRET?.trim() || undefined;
 72→  const betterAuthSecret = requireEnv("BETTER_AUTH_SECRET");
 73→  const betterAuthUrl = requireEnv("BETTER_AUTH_URL");
 74→  const githubClientId = requireEnv("GITHUB_CLIENT_ID");
 75→  const githubClientSecret = requireEnv("GITHUB_CLIENT_SECRET");
 76→
 77→  return {
 78→    openRouterApiKey,
 79→    chatAgentModelId,
 80→    extractionModelId,
 81→    pmAgentModelId,
 82→    analyticsAgentModelId,
 83→    embeddingModelId,
 84→    embeddingDimension,
 85→    extractionStoreThreshold,
 86→    extractionDisplayThreshold,
 87→    openRouterReasoning: parseOpenRouterReasoning(),
 88→    surrealUrl,
 89→    surrealUsername,
 90→    surrealPassword,
 91→    surrealNamespace,
 92→    surrealDatabase,
 93→    port,
 94→    ...(observerModelId ? { observerModelId } : {}),
 95→    ...(githubWebhookSecret ? { githubWebhookSecret } : {}),
 96→    betterAuthSecret,
 97→    betterAuthUrl,
 98→    githubClientId,
 99→    githubClientSecret,
100→  };
101→}
