103→function requireEnv(name: string): string {
104→  const value = Bun.env[name];
105→  if (!value || value.trim().length === 0) {
106→    throw new Error(`${name} is required`);
107→  }
108→
109→  return value;
110→}
111→
112→function parsePositiveInteger(value: string, envName: string): number {
113→  const parsed = Number(value);
114→  if (!Number.isInteger(parsed) || parsed < 1) {
115→    throw new Error(`${envName} must be a positive integer`);
116→  }
117→  return parsed;
118→}
119→
120→function parseUnitInterval(value: string, envName: string): number {
121→  const parsed = Number(value);
122→  if (!Number.isFinite(parsed) || parsed < 0 || parsed > 1) {
123→    throw new Error(`${envName} must be a number between 0 and 1`);
124→  }
125→
126→  return parsed;
127→}
128→
129→function parseOpenRouterReasoning(): OpenRouterReasoningOptions | undefined {
130→  const effortValue = Bun.env.OPENROUTER_REASONING_EFFORT;
131→  const maxTokensValue = Bun.env.OPENROUTER_REASONING_MAX_TOKENS;
132→
133→  if (!effortValue && !maxTokensValue) {
134→    return undefined;
135→  }
136→
137→  const reasoning: OpenRouterReasoningOptions = {};
138→
139→  if (effortValue) {
140→    const allowedEfforts: OpenRouterReasoningEffort[] = ["xhigh", "high", "medium", "low", "minimal", "none"];
141→
142→    if (!allowedEfforts.includes(effortValue as OpenRouterReasoningEffort)) {
143→      throw new Error("OPENROUTER_REASONING_EFFORT must be one of xhigh, high, medium, low, minimal, none");
144→    }
145→    reasoning.effort = effortValue as OpenRouterReasoningEffort;
146→  }
147→
148→  if (maxTokensValue) {
149→    const parsed = Number(maxTokensValue);
150→    if (!Number.isFinite(parsed) || parsed < 1) {
151→      throw new Error("OPENROUTER_REASONING_MAX_TOKENS must be a positive number");
152→    }
153→    reasoning.max_tokens = parsed;
154→  }
155→
156→  return reasoning;
157→}
