116→async function queryCompletedTasks(
117→  surreal: Surreal,
118→  workspaceRecord: RecordId<"workspace", string>,
119→): Promise<CompletedTask[]> {
120→  const [rows] = await surreal.query<[CompletedTask[]]>(
121→    `SELECT id, title, description, updated_at FROM task
122→     WHERE workspace = $ws AND status IN ["completed", "done"]
123→     ORDER BY updated_at DESC
124→     LIMIT 50;`,
125→    { ws: workspaceRecord },
126→  );
127→  return rows ?? [];
128→}
