130→async function queryStaleBlockedTasks(
131→  surreal: Surreal,
132→  workspaceRecord: RecordId<"workspace", string>,
133→): Promise<StaleBlockedTask[]> {
134→  const thresholdDate = new Date(
135→    Date.now() - STALE_BLOCKED_THRESHOLD_DAYS * 24 * 60 * 60 * 1000,
136→  );
137→
138→  const [rows] = await surreal.query<
139→    [Array<{ id: RecordId<"task">; title: string; description?: string; updated_at: string }>]
140→  >(
141→    `SELECT id, title, description, updated_at FROM task
142→     WHERE workspace = $ws
143→       AND status = "blocked"
144→       AND updated_at < $threshold
145→     ORDER BY updated_at ASC
146→     LIMIT 50;`,
147→    { ws: workspaceRecord, threshold: thresholdDate },
148→  );
149→
150→  return (rows ?? []).map((row) => {
151→    const updatedAt = new Date(row.updated_at);
152→    const daysBlocked = Math.floor(
153→      (Date.now() - updatedAt.getTime()) / (24 * 60 * 60 * 1000),
154→    );
155→    return { ...row, daysBlocked };
156→  });
157→}
