159→async function queryStatusDriftTasks(
160→  surreal: Surreal,
161→  workspaceRecord: RecordId<"workspace", string>,
162→): Promise<StatusDriftTask[]> {
163→  // Two-step approach: first find completed tasks with dependencies,
164→  // then filter for incomplete dependencies in application code
165→  const [rows] = await surreal.query<[Array<{
166→    id: RecordId<"task">;
167→    title: string;
168→    status: string;
169→    dep_ids: RecordId<"task">[];
170→    dep_titles: string[];
171→    dep_statuses: string[];
172→  }>]>(
173→    `SELECT
174→       id, title, status,
175→       ->depends_on->task.id AS dep_ids,
176→       ->depends_on->task.title AS dep_titles,
177→       ->depends_on->task.status AS dep_statuses
178→     FROM task
179→     WHERE workspace = $ws
180→       AND status IN ["completed", "done"]
181→       AND array::len(->depends_on->task) > 0
182→     LIMIT 50;`,
183→    { ws: workspaceRecord },
184→  );
185→
186→  return (rows ?? []).flatMap((row) => {
187→    const depIds = row.dep_ids ?? [];
188→    const depTitles = row.dep_titles ?? [];
189→    const depStatuses = row.dep_statuses ?? [];
190→
191→    const drifts: StatusDriftTask[] = [];
192→    for (let i = 0; i < depIds.length; i++) {
193→      const depStatus = depStatuses[i];
194→      if (depStatus !== "completed" && depStatus !== "done") {
195→        drifts.push({
196→          id: row.id,
197→          title: row.title,
198→          status: row.status,
199→          dependency: {
200→            id: depIds[i],
201→            title: depTitles[i],
202→            status: depStatus,
203→          },
204→        });
205→      }
206→    }
207→    return drifts;
208→  });
209→}
