 57→// ---------------------------------------------------------------------------
 58→// Configuration
 59→// ---------------------------------------------------------------------------
 60→
 61→const CLUSTER_SIMILARITY_THRESHOLD = 0.75;
 62→const MINIMUM_CLUSTER_SIZE = 3;
 63→const TIME_WINDOW_DAYS = 14;
 64→// Coverage threshold is lower than typical dedup thresholds (0.85) because
 65→// we compare observation-text centroids (descriptive, noisy) against learning-text
 66→// embeddings (directive, concise). Cross-form comparisons consistently score
 67→// 30-40% lower on cosine similarity than same-form comparisons.
 68→const COVERAGE_SIMILARITY_THRESHOLD = 0.50;
 69→// Same cross-domain text form issue as coverage threshold — observation
 70→// centroids vs dismissed learning embeddings. Lower than the dismissed
 71→// re-suggestion gate (0.85) in suggestLearning() which compares same-form texts.
 72→const DISMISSED_PATTERN_SIMILARITY_THRESHOLD = 0.50;
 73→
 74→// ---------------------------------------------------------------------------
 75→// Observation query (IO boundary)
 76→// ---------------------------------------------------------------------------
 77→
 78→/**
 79→ * Queries open/acknowledged observations from the past 14 days with embeddings.
 80→ * Uses two-step KNN pattern per SurrealDB HNSW+WHERE bug.
 81→ */
 82→export async function queryRecentObservationsWithEmbeddings(
 83→  surreal: Surreal,
 84→  workspaceRecord: RecordId<"workspace", string>,
 85→): Promise<ObservationWithEmbedding[]> {
 86→  const cutoff = new Date(Date.now() - TIME_WINDOW_DAYS * 24 * 60 * 60 * 1000);
 87→
 88→  const [rows] = await surreal.query<[Array<{
 89→    id: RecordId<"observation">;
 90→    text: string;
 91→    severity: string;
 92→    embedding: number[];
 93→    entity_refs: Array<RecordId | string>;
 94→    created_at: string;
 95→  }>]>(
 96→    `SELECT id, text, severity, embedding, created_at,
 97→            ->observes->task.id AS entity_refs
 98→     FROM observation
 99→     WHERE workspace = $ws
100→       AND status IN ["open", "acknowledged"]
101→       AND created_at > $cutoff
102→       AND embedding IS NOT NONE
103→     ORDER BY created_at DESC
104→     LIMIT 200;`,
105→    { ws: workspaceRecord, cutoff },
106→  );
107→
108→  return (rows ?? []).map((row) => ({
109→    id: row.id.id as string,
110→    text: row.text,
111→    severity: row.severity,
112→    embedding: row.embedding,
113→    entityRefs: (row.entity_refs ?? [])
114→      .filter((ref): ref is RecordId => typeof ref === "object" && ref !== null && "id" in ref)
115→      .map((ref) => `task:${ref.id as string}`),
116→  }));
117→}
118→
119→// ---------------------------------------------------------------------------
120→// Pure clustering (no IO)
121→// ---------------------------------------------------------------------------
122→
123→/**
124→ * Clusters observations by pairwise embedding similarity using single-linkage.
125→ *
126→ * Algorithm:
127→ * 1. Build adjacency: observation A is neighbor of B if similarity > threshold
128→ * 2. Connected components via BFS form clusters
129→ * 3. Filter clusters by minimum size
130→ *
131→ * Pure function -- no IO.
132→ */
133→export function clusterObservationsBySimilarity(
134→  observations: ObservationWithEmbedding[],
135→  similarityThreshold: number = CLUSTER_SIMILARITY_THRESHOLD,
136→  minimumClusterSize: number = MINIMUM_CLUSTER_SIZE,
137→): ObservationCluster[] {
138→  if (observations.length < minimumClusterSize) return [];
139→
140→  // Build adjacency list
141→  const adjacency = new Map<number, Set<number>>();
142→  for (let i = 0; i < observations.length; i++) {
143→    adjacency.set(i, new Set());
144→  }
145→
146→  for (let i = 0; i < observations.length; i++) {
147→    for (let j = i + 1; j < observations.length; j++) {
148→      const similarity = cosineSimilarity(
149→        observations[i].embedding,
150→        observations[j].embedding,
151→      );
152→      if (similarity > similarityThreshold) {
153→        adjacency.get(i)!.add(j);
154→        adjacency.get(j)!.add(i);
155→      }
156→    }
157→  }
158→
159→  // BFS to find connected components
160→  const visited = new Set<number>();
161→  const clusters: ObservationCluster[] = [];
162→
163→  for (let i = 0; i < observations.length; i++) {
164→    if (visited.has(i)) continue;
165→
166→    const component: number[] = [];
167→    const queue = [i];
168→    visited.add(i);
169→
170→    while (queue.length > 0) {
171→      const current = queue.shift()!;
172→      component.push(current);
173→
174→      for (const neighbor of adjacency.get(current)!) {
175→        if (!visited.has(neighbor)) {
176→          visited.add(neighbor);
177→          queue.push(neighbor);
178→        }
179→      }
180→    }
181→
182→    if (component.length >= minimumClusterSize) {
183→      const clusterObservations = component.map((idx) => ({
184→        id: observations[idx].id,
185→        text: observations[idx].text,
186→        severity: observations[idx].severity,
187→        entityRefs: observations[idx].entityRefs,
188→      }));
189→
190→      // Representative text: the observation with highest average similarity to others in cluster
191→      const representativeIndex = pickRepresentativeIndex(component, observations);
192→
193→      clusters.push({
194→        observations: clusterObservations,
195→        representativeText: observations[representativeIndex].text,
196→        clusterSize: component.length,
197→      });
198→    }
199→  }
200→
201→  return clusters;
202→}
203→
204→/**
205→ * Computes the centroid (element-wise average) of a set of embedding vectors.
206→ * This reduces noise from individual observation text variations, producing
207→ * a more representative embedding for cluster-level similarity comparisons.
208→ */
209→function computeCentroidEmbedding(embeddings: number[][]): number[] {
210→  if (embeddings.length === 0) return [];
211→  if (embeddings.length === 1) return embeddings[0];
212→
213→  const dimension = embeddings[0].length;
214→  const centroid = new Array<number>(dimension).fill(0);
215→
216→  for (const embedding of embeddings) {
217→    for (let i = 0; i < dimension; i++) {
218→      centroid[i] += embedding[i];
219→    }
220→  }
221→
222→  for (let i = 0; i < dimension; i++) {
223→    centroid[i] /= embeddings.length;
224→  }
225→
226→  return centroid;
227→}
228→
229→/**
230→ * Picks the observation with highest average similarity to other cluster members.
231→ */
232→function pickRepresentativeIndex(
233→  componentIndices: number[],
234→  observations: ObservationWithEmbedding[],
235→): number {
236→  let bestIndex = componentIndices[0];
237→  let bestAvgSimilarity = -1;
238→
239→  for (const i of componentIndices) {
240→    let totalSimilarity = 0;
241→    for (const j of componentIndices) {
242→      if (i !== j) {
243→        totalSimilarity += cosineSimilarity(
244→          observations[i].embedding,
245→          observations[j].embedding,
246→        );
247→      }
248→    }
249→    const avgSimilarity = totalSimilarity / (componentIndices.length - 1);
250→    if (avgSimilarity > bestAvgSimilarity) {
251→      bestAvgSimilarity = avgSimilarity;
252→      bestIndex = i;
253→    }
254→  }
255→
256→  return bestIndex;
257→}
