259→// ---------------------------------------------------------------------------
260→// Coverage check (IO boundary -- KNN query)
261→// ---------------------------------------------------------------------------
262→
263→/**
264→ * Checks if any learning with a given status covers the cluster pattern.
265→ * Uses two-step KNN pattern per SurrealDB HNSW+WHERE bug, with brute-force fallback.
266→ */
267→async function checkLearningCoverage(
268→  surreal: Surreal,
269→  workspaceRecord: RecordId<"workspace", string>,
270→  clusterEmbedding: number[],
271→  learningStatus: "active" | "dismissed",
272→  similarityThreshold: number,
273→): Promise<CoverageCheckResult> {
274→  const results = await surreal
275→    .query<[undefined, Array<{ text: string; similarity: number }>]>(
276→      [
277→        "LET $candidates = SELECT id, text, workspace, status,",
278→        "vector::similarity::cosine(embedding, $embedding) AS similarity",
279→        "FROM learning WHERE embedding <|10, COSINE|> $embedding;",
280→        "SELECT text, similarity FROM $candidates",
281→        "WHERE workspace = $ws AND status = $status AND similarity > $threshold",
282→        "ORDER BY similarity DESC LIMIT 1;",
283→      ].join("\n"),
284→      {
285→        embedding: clusterEmbedding,
286→        ws: workspaceRecord,
287→        status: learningStatus,
288→        threshold: similarityThreshold,
289→      },
290→    );
291→
292→  const matches = results[1] ?? [];
293→  const match = matches[0];
294→  if (match) {
295→    return { covered: true, matchedLearningText: match.text, similarity: match.similarity };
296→  }
297→
298→  // Brute-force fallback when HNSW index hasn't indexed recent inserts
299→  const [learnings] = await surreal.query<[Array<{ text: string; embedding: number[] }>]>(
300→    `SELECT text, embedding FROM learning
301→     WHERE workspace = $ws
302→       AND status = $status
303→       AND embedding IS NOT NONE;`,
304→    { ws: workspaceRecord, status: learningStatus },
305→  );
306→
307→  if (learningStatus === "active") {
308→    logInfo("observer.learning.coverage_fallback", "Fallback coverage check", {
309→      activeLearningsCount: (learnings ?? []).length,
310→      workspaceId: workspaceRecord.id,
311→    });
312→  }
313→
314→  for (const learning of learnings ?? []) {
315→    const similarity = cosineSimilarity(clusterEmbedding, learning.embedding);
316→    if (similarity > similarityThreshold) {
317→      return { covered: true, matchedLearningText: learning.text, similarity };
318→    }
319→  }
320→
321→  return { covered: false };
322→}
323→
324→export async function checkCoverageAgainstActiveLearnings(
325→  surreal: Surreal,
326→  workspaceRecord: RecordId<"workspace", string>,
327→  clusterEmbedding: number[],
328→): Promise<CoverageCheckResult> {
329→  return checkLearningCoverage(surreal, workspaceRecord, clusterEmbedding, "active", COVERAGE_SIMILARITY_THRESHOLD);
330→}
331→
332→export async function checkDismissedLearningForCluster(
333→  surreal: Surreal,
334→  workspaceRecord: RecordId<"workspace", string>,
335→  clusterEmbedding: number[],
336→): Promise<CoverageCheckResult> {
337→  return checkLearningCoverage(surreal, workspaceRecord, clusterEmbedding, "dismissed", DISMISSED_PATTERN_SIMILARITY_THRESHOLD);
338→}
