532→/**
533→ * Queries all behavior records in a workspace, groups by identity + metric type,
534→ * and analyzes trends for each group.
535→ *
536→ * Returns only groups with enough data points for trend analysis.
537→ */
538→export async function queryWorkspaceBehaviorTrends(
539→  surreal: Surreal,
540→  workspaceRecord: RecordId<"workspace", string>,
541→): Promise<BehaviorTrendEntry[]> {
542→  // Query all behavior records with their identity via exhibits edges
543→  const [rows] = await surreal.query<[Array<{
544→    id: RecordId<"behavior">;
545→    metric_type: string;
546→    score: number;
547→    created_at: string;
548→    identity_id: RecordId<"identity">[];
549→  }>]>(
550→    `SELECT id, metric_type, score, created_at,
551→            <-exhibits<-identity.id AS identity_id
552→     FROM behavior
553→     WHERE workspace = $ws
554→     ORDER BY created_at ASC;`,
555→    { ws: workspaceRecord },
556→  );
557→
558→  if (!rows || rows.length === 0) return [];
559→
560→  // Group by identity + metric_type
561→  const groups = new Map<string, {
562→    identityId: string;
563→    metricType: string;
564→    points: ScorePoint[];
565→    behaviorIds: string[];
566→  }>();
567→
568→  for (const row of rows) {
569→    const identityIds = row.identity_id ?? [];
570→    if (identityIds.length === 0) continue;
571→
572→    const identityId = identityIds[0].id as string;
573→    const key = `${identityId}::${row.metric_type}`;
574→
575→    if (!groups.has(key)) {
576→      groups.set(key, {
577→        identityId,
578→        metricType: row.metric_type,
579→        points: [],
580→        behaviorIds: [],
581→      });
582→    }
583→
584→    const group = groups.get(key)!;
585→    group.points.push({ score: row.score, timestamp: row.created_at });
586→    group.behaviorIds.push(row.id.id as string);
587→  }
588→
589→  // Analyze trend for each group
590→  const entries: BehaviorTrendEntry[] = [];
591→  for (const group of groups.values()) {
592→    const trend = analyzeTrend(group.points);
593→    entries.push({
594→      identityId: group.identityId,
595→      metricType: group.metricType,
596→      trend,
597→      behaviorIds: group.behaviorIds,
598→      scorePoints: group.points,
599→    });
600→  }
601→
602→  return entries;
603→}
