620→/**
621→ * Composes a learning proposal from behavior trend data and submits it
622→ * via the existing suggestLearning pipeline (with rate limit + collision detection).
623→ *
624→ * Behavior records are linked as learning_evidence via the extended relation OUT.
625→ */
626→export async function proposeBehaviorLearning(
627→  input: ProposeBehaviorLearningInput,
628→): Promise<ProposeBehaviorLearningResult> {
629→  const learningText = buildBehaviorLearningText(
630→    input.identityId,
631→    input.metricType,
632→    input.trendPattern,
633→  );
634→
635→  const learningInput: CreateLearningInput = {
636→    text: learningText,
637→    learningType: "constraint",
638→    source: "agent",
639→    suggestedBy: "observer",
640→    patternConfidence: 0.80,
641→    targetAgents: [input.identityId],
642→    evidenceIds: input.behaviorIds.map((id) => ({
643→      table: "behavior" as const,
644→      id,
645→    })),
646→  };
647→
648→  const result = await suggestLearning({
649→    surreal: input.surreal,
650→    workspaceRecord: input.workspaceRecord,
651→    learning: learningInput,
652→    now: input.now,
653→  });
654→
655→  if (result.created) {
656→    logInfo("observer.behavior.learning_proposed", "Learning proposed from behavior trend", {
657→      identityId: input.identityId,
658→      metricType: input.metricType,
659→      trendPattern: input.trendPattern,
660→      learningId: result.learningRecord.id,
661→    });
662→    return { created: true, learningRecord: result.learningRecord };
663→  }
664→
665→  logInfo("observer.behavior.learning_blocked", "Behavior learning proposal blocked", {
666→    identityId: input.identityId,
667→    metricType: input.metricType,
668→    reason: result.reason,
669→  });
670→
671→  return result;
