674→/**
675→ * Builds a descriptive learning text from behavior trend data.
676→ * Pure function -- no IO.
677→ */
678→function buildBehaviorLearningText(
679→  identityId: string,
680→  metricType: string,
681→  trendPattern: TrendPattern,
682→): string {
683→  const metricLabel = metricType.replace(/_/g, " ");
684→
685→  switch (trendPattern) {
686→    case "drift":
687→      return `Agent ${identityId} shows sustained decline in ${metricLabel}. ` +
688→        `Enforce ${metricLabel} standards before proceeding with other work.`;
689→    case "flat":
690→      return `Agent ${identityId} shows persistent stagnation in ${metricLabel} below threshold. ` +
691→        `Current learning interventions for ${metricLabel} are ineffective -- consider revising approach.`;
692→    default:
693→      return `Agent ${identityId} shows concerning ${trendPattern} pattern in ${metricLabel}. ` +
694→        `Review ${metricLabel} compliance and reinforce expected behavior.`;
695→  }
696→}
