698→// ---------------------------------------------------------------------------
699→// Process a single uncovered cluster: classify and propose or observe
700→// ---------------------------------------------------------------------------
701→
702→async function processUncoveredCluster(
703→  surreal: Surreal,
704→  workspaceRecord: RecordId<"workspace", string>,
705→  model: LanguageModel,
706→  cluster: ObservationCluster,
707→  existingLearnings: string[],
708→  embeddingModel?: EmbeddingModel,
709→  embeddingDimension?: number,
710→): Promise<{ proposed: boolean }> {
711→  const classification = await classifyRootCause(model, cluster, existingLearnings);
712→
713→  if (!classification) {
714→    logInfo("observer.learning.classification_skipped", "Skipping cluster due to failed LLM classification", {
715→      clusterSize: cluster.clusterSize,
716→      representativeText: cluster.representativeText.slice(0, 100),
717→    });
718→    return { proposed: false };
719→  }
720→
721→  if (shouldProposeLearning(classification)) {
722→    const learningInput = rootCauseToLearningInput(classification, cluster);
723→
724→    // Generate embedding for the proposed learning text to enable
725→    // dismissed similarity gate and persist with the learning record
726→    const embedding = embeddingModel && embeddingDimension
727→      ? await createEmbeddingVector(embeddingModel, learningInput.text, embeddingDimension)
728→      : undefined;
729→
730→    const result = await suggestLearning({
731→      surreal,
732→      workspaceRecord,
733→      learning: learningInput,
734→      embedding,
735→      now: new Date(),
736→    });
737→
738→    if (result.created) {
739→      logInfo("observer.learning.proposed", "Learning proposed from root cause analysis", {
740→        category: classification.category,
741→        confidence: classification.confidence,
742→        learningType: classification.proposed_learning_type,
743→        learningId: result.learningRecord.id,
744→      });
745→      return { proposed: true };
746→    }
747→
748→    logInfo("observer.learning.gate_blocked", "Learning proposal blocked by safety gate", {
749→      reason: result.reason,
750→    });
751→    return { proposed: false };
752→  }
753→
754→  // Dual gate failed: create an observation instead
755→  await createObservation({
756→    surreal,
757→    workspaceRecord,
758→    text: `Emerging pattern detected but root cause unclear (${classification.category}, confidence: ${classification.confidence.toFixed(2)}): ${classification.reasoning}`,
759→    severity: "info",
760→    sourceAgent: "observer_agent",
761→    observationType: "pattern",
762→    now: new Date(),
763→  });
764→
765→  logInfo("observer.learning.low_confidence", "Pattern observed but confidence too low for learning proposal", {
766→    category: classification.category,
767→    confidence: classification.confidence,
768→    shouldPropose: classification.should_propose_learning,
769→  });
770→
771→  return { proposed: false };
772→}
