774→// ---------------------------------------------------------------------------
775→// Diagnostic pipeline orchestrator
776→// ---------------------------------------------------------------------------
777→
778→/**
779→ * Runs the observation clustering, coverage check, and root cause classification pipeline.
780→ *
781→ * Pipeline:
782→ * 1. Query recent observations with embeddings
783→ * 2. Cluster by pairwise similarity
784→ * 3. For each cluster, check coverage against active learnings
785→ * 4. For uncovered clusters, classify root cause via LLM
786→ * 5. Propose learning or create observation based on dual gate
787→ */
788→export async function runDiagnosticClustering(
789→  surreal: Surreal,
790→  workspaceRecord: RecordId<"workspace", string>,
791→  observerModel: LanguageModel,
792→  embeddingModel: EmbeddingModel,
793→  embeddingDimension: number,
794→): Promise<{
795→  clusters: ObservationCluster[];
796→  uncoveredClusters: ObservationCluster[];
797→  result: DiagnosticResult;
798→}> {
799→  const diagnosticResult: DiagnosticResult = {
800→    learning_proposals_created: 0,
801→    coverage_skips: 0,
802→    clusters_found: 0,
803→  };
804→
805→  // Step 1: Query recent observations
806→  const observations = await queryRecentObservationsWithEmbeddings(
807→    surreal,
808→    workspaceRecord,
809→  );
810→
811→  if (observations.length < MINIMUM_CLUSTER_SIZE) {
812→    return { clusters: [], uncoveredClusters: [], result: diagnosticResult };
813→  }
814→
815→  // Step 2: Cluster by similarity (pure)
816→  const clusters = clusterObservationsBySimilarity(observations);
817→  diagnosticResult.clusters_found = clusters.length;
818→
819→  if (clusters.length === 0) {
820→    return { clusters: [], uncoveredClusters: [], result: diagnosticResult };
821→  }
822→
823→  // Step 3: Coverage check for each cluster
824→  const uncoveredClusters: ObservationCluster[] = [];
825→
826→  for (const cluster of clusters) {
827→    // Compute cluster centroid embedding (average of all observation embeddings)
828→    // to reduce noise from individual observation text variations
829→    const clusterObsWithEmbeddings = cluster.observations
830→      .map((co) => observations.find((o) => o.id === co.id))
831→      .filter((o): o is ObservationWithEmbedding => o !== undefined && o.embedding.length > 0);
832→
833→    if (clusterObsWithEmbeddings.length === 0) {
834→      uncoveredClusters.push(cluster);
835→      continue;
836→    }
837→
838→    const centroidEmbedding = computeCentroidEmbedding(
839→      clusterObsWithEmbeddings.map((o) => o.embedding),
840→    );
841→
842→    const coverage = await checkCoverageAgainstActiveLearnings(
843→      surreal,
844→      workspaceRecord,
845→      centroidEmbedding,
846→    );
847→
848→    if (coverage.covered) {
849→      logInfo("observer.learning.coverage_skip", "Cluster pattern already covered by active learning", {
850→        clusterSize: cluster.clusterSize,
851→        matchedLearningText: coverage.matchedLearningText,
852→        similarity: coverage.similarity,
853→      });
854→      diagnosticResult.coverage_skips += 1;
855→      continue;
856→    }
857→
858→    // Check if a dismissed learning already covers this pattern
859→    const dismissedCheck = await checkDismissedLearningForCluster(
860→      surreal,
861→      workspaceRecord,
862→      centroidEmbedding,
863→    );
864→
865→    if (dismissedCheck.covered) {
866→      logInfo("observer.learning.dismissed_skip", "Cluster pattern matches a previously dismissed learning", {
867→        clusterSize: cluster.clusterSize,
868→        matchedLearningText: dismissedCheck.matchedLearningText,
869→        similarity: dismissedCheck.similarity,
870→      });
871→      diagnosticResult.coverage_skips += 1;
872→    } else {
873→      uncoveredClusters.push(cluster);
874→    }
875→  }
876→
877→  // Step 4: Root cause classification for uncovered clusters
878→  if (uncoveredClusters.length > 0) {
879→    const existingLearnings = await queryActiveLearningTexts(surreal, workspaceRecord);
880→
881→    for (const cluster of uncoveredClusters) {
882→      const { proposed } = await processUncoveredCluster(
883→        surreal,
884→        workspaceRecord,
885→        observerModel,
886→        cluster,
887→        existingLearnings,
888→        embeddingModel,
889→        embeddingDimension,
890→      );
891→
892→      if (proposed) {
893→        diagnosticResult.learning_proposals_created += 1;
894→      }
895→    }
896→  }
897→
898→  return { clusters, uncoveredClusters, result: diagnosticResult };
899→}
