  1→import type {
  2→  RulePredicate,
  3→  RuleCondition,
  4→  PolicyGateWarning,
  5→} from "./types";
  6→
  7→// ---------------------------------------------------------------------------
  8→// Dot-Path Resolution
  9→// ---------------------------------------------------------------------------
 10→
 11→export const resolveDotPath = (
 12→  context: Record<string, unknown>,
 13→  path: string,
 14→): unknown | undefined => {
 15→  const segments = path.split(".");
 16→  let current: unknown = context;
 17→
 18→  for (const segment of segments) {
 19→    if (current === null) {
 20→      throw new Error(`Contract violation: null encountered in context at segment '${segment}'`);
 21→    }
 22→    if (current === undefined || typeof current !== "object") {
 23→      return undefined;
 24→    }
 25→    current = (current as Record<string, unknown>)[segment];
 26→  }
 27→
 28→  return current;
 29→};
 30→
 31→// ---------------------------------------------------------------------------
 32→// Predicate Evaluation (single predicate -> boolean)
 33→// ---------------------------------------------------------------------------
 34→
 35→const applyOperator = (
 36→  resolved: unknown,
 37→  operator: RulePredicate["operator"],
 38→  value: RulePredicate["value"],
 39→): boolean => {
 40→  switch (operator) {
 41→    case "eq":
 42→      return resolved === value;
 43→    case "neq":
 44→      return resolved !== value;
 45→    case "lt":
 46→      return typeof resolved === "number" && typeof value === "number" && resolved < value;
 47→    case "lte":
 48→      return typeof resolved === "number" && typeof value === "number" && resolved <= value;
 49→    case "gt":
 50→      return typeof resolved === "number" && typeof value === "number" && resolved > value;
 51→    case "gte":
 52→      return typeof resolved === "number" && typeof value === "number" && resolved >= value;
 53→    case "in":
 54→      return Array.isArray(value) && value.includes(resolved as string);
 55→    case "not_in":
 56→      return Array.isArray(value) && !value.includes(resolved as string);
 57→    case "exists":
 58→      return resolved !== undefined;
 59→  }
 60→};
 61→
 62→export const evaluatePredicate = (
 63→  context: Record<string, unknown>,
 64→  predicate: RulePredicate,
 65→): boolean => {
 66→  const resolved = resolveDotPath(context, predicate.field);
 67→
 68→  if (resolved === undefined && predicate.operator !== "exists") {
 69→    return false;
 70→  }
 71→
 72→  return applyOperator(resolved, predicate.operator, predicate.value);
 73→};
 74→
 75→// ---------------------------------------------------------------------------
 76→// Condition Evaluation (single or AND-array -> matched + warnings)
 77→// ---------------------------------------------------------------------------
 78→
 79→const isPredicateArray = (condition: RuleCondition): condition is RulePredicate[] =>
 80→  Array.isArray(condition);
 81→
 82→const fieldIsMissing = (
 83→  context: Record<string, unknown>,
 84→  field: string,
 85→): boolean => resolveDotPath(context, field) === undefined;
 86→
 87→const collectWarning = (
 88→  context: Record<string, unknown>,
 89→  predicate: RulePredicate,
 90→  ruleId: string,
 91→  policyId: string,
 92→): PolicyGateWarning | undefined =>
 93→  fieldIsMissing(context, predicate.field)
 94→    ? { rule_id: ruleId, field: predicate.field, policy_id: policyId }
 95→    : undefined;
 96→
 97→export const evaluateCondition = (
 98→  context: Record<string, unknown>,
 99→  condition: RuleCondition,
100→  ruleId: string,
101→  policyId: string,
102→): { matched: boolean; warnings: PolicyGateWarning[] } => {
103→  const predicates = isPredicateArray(condition) ? condition : [condition];
104→
105→  const warnings = predicates
106→    .map((predicate) => collectWarning(context, predicate, ruleId, policyId))
107→    .filter((warning): warning is PolicyGateWarning => warning !== undefined);
108→
109→  const matched = predicates.every((predicate) =>
110→    evaluatePredicate(context, predicate),
111→  );
112→
113→  return { matched, warnings };
114→};
